function pickWeight(weight: Weight = "duotone") {
  if (weight === "regular" || weight === "Linear") return "Linear";
  if (weight === "fill" || weight === "Bold") return "Bold";
  return "BoldDuotone";
}

function renderNode(node: IconNode): ReactNode {
  if (node == null || typeof node === "string" || typeof node === "number") return node;
  if (Array.isArray(node)) {
    return (node as readonly IconNode[]).map((child, index) => <Fragment key={index}>{renderNode(child)}</Fragment>);
  }
  const element = node as { readonly type: string; readonly props?: Record<string, unknown>; readonly children?: IconNode };
  const Type = element.type === "fragment" ? Fragment : element.type;
  return createElement(Type, element.props || {}, renderNode(element.children ?? null));
}

function makeIcon(name: keyof typeof iconData) {
  return function SolarIcon({ size = 20, weight = "duotone", className, ...props }: IconProps) {
    return (
      <svg width={size} height={size} viewBox="0 0 24 24" fill="none" className={className} aria-hidden={props["aria-hidden"] ?? true}>
        {renderNode(iconData[name][pickWeight(weight)])}
      </svg>
    );
  };
}

